(() => {
  const $ = id => document.getElementById(id);
  const state = { phase: 0, opened: false, cleared: false, challenged: false, finalized: false, docket: null };
  const stages = ['Sponsor mandate','Paymaster budget envelope','NettingHouse receipt batch','Alpha-Factory work swarm','ProofBundle export','Challenge window','AGIJobManager checkpoint','Chronicle handoff'];
  const presets = {
    invention: 'Generate and screen public-safe invention candidates, quarantine uncertain descendants, export proof roots, and send only review-ready artifacts to Chronicle.',
    software: 'Batch a software repair mandate into proof receipts: patch proposals, tests, validator decisions, cost ledgers, and rollback-ready candidate artifacts.',
    research: 'Produce a public-safe research Evidence Docket with claims matrix, source provenance, contradiction register, replay path, and review brief.',
    market: 'Create a proof-settled market intelligence packet with bounded research jobs, validator checks, uncertainty ledger, and Chronicle-ready insights.',
    security: 'Run a defensive, repo-owned security review mandate with safe scope, evidence-only findings, red-team review, and no external target activity.'
  };
  const rootNames = ['receiptRoot','payoutRoot','archiveDeltaRoot','quarantineRoot'];
  function hash(s){ let h = 2166136261; for(let i=0;i<s.length;i++){ h ^= s.charCodeAt(i); h = Math.imul(h,16777619); } return ('00000000'+(h>>>0).toString(16)).slice(-8); }
  function rid(prefix, seed){ return prefix + '-' + hash(seed).toUpperCase() + hash(seed+'x').toUpperCase().slice(0,6); }
  function vals(){ return { preset:$('mandatePreset').value, objective:$('mandateObjective').value.trim(), microjobs:+$('microjobs').value, replay:+$('replay').value, quorum:+$('quorum').value, dispute:+$('dispute').value, redteam:+$('redteam').value, boundary:+$('boundary').value, quality:+$('quality').value }; }
  function updateSliderLabels(){ document.querySelectorAll('.me-sliders label').forEach(label => { const input = label.querySelector('input'); const span = label.querySelector('span'); if(span && input) span.textContent = input.value; }); }
  function trace(line){ const box=$('traceLog'); const time = new Date().toISOString().slice(11,19); box.textContent += `[${time}] ${line}\n`; box.scrollTop = box.scrollHeight; }
  function renderStages(active=0){ $('stageRail').innerHTML = stages.map((s,i)=>`<div class="me-stage ${i<active?'done':''} ${i===active?'active':''}"><span>${String(i+1).padStart(2,'0')}</span><div><b>${s}</b><small>${i<active?'complete':i===active?'running':'queued'}</small></div><em>${i<active?'✓':i===active?'•':'—'}</em></div>`).join(''); }
  function compute(){ const v=vals(); const rejected = Math.max(0, Math.round(v.microjobs * ((100-v.replay)/260 + v.dispute/420 + (100-v.redteam)/700))); const quarantined = Math.max(0, Math.round(v.microjobs * ((100-v.boundary)/250 + v.dispute/600))); const disputed = Math.max(0, Math.round(v.microjobs * (v.dispute/500))); const accepted = Math.max(0, v.microjobs - rejected - quarantined); const awu = Math.max(0, Math.round(accepted * (v.quality/100) * (v.replay/100) * (v.boundary/100) * 100)/10); const clear = accepted >= Math.ceil(v.microjobs*.62) && v.replay>=70 && v.quorum>=3 && v.boundary>=82 && v.redteam>=55; const outcome = !state.finalized ? (state.challenged?'CHALLENGE_WINDOW_OPEN':state.cleared?'RECEIPTS_CLEARED':'EPOCH_OPEN') : (clear?'FINALIZE_REVIEW_READY':'HOLD_FOR_MORE_PROOF'); const seed = JSON.stringify(v)+accepted+quarantined+disputed+awu; const roots = Object.fromEntries(rootNames.map(n=>[n,'0x'+hash(n+seed)+hash(seed+n)+hash(n+':'+seed)+hash(seed+':'+n)])); return {...v, accepted, rejected, quarantined, disputed, awu, clear, outcome, roots, epochId: rid('ME', seed), mandateHash:'0x'+hash('mandate'+seed)+hash(seed+'mandate')}; }
  function docket(){ const c=compute(); return { type:'MandateEpochReceipt', version:'v26-public-demo', generatedAt:new Date().toISOString(), productionUrl:'https://montrealai.github.io/goalos-agijobmanager-ascension/mandate-epoch-clearinghouse.html', boundary:{browserLocal:true,noUserDataWanted:true,noAccount:true,noCookies:true,noAnalytics:true,noStorage:true,noWallet:true,noNetwork:true,noTransactionBroadcast:true,noProductionAuthority:true}, mandate:{epochId:c.epochId, archetype:c.preset, objective:c.objective, mandateHash:c.mandateHash}, publicRoots:c.roots, clearing:{microjobReceipts:c.microjobs, acceptedReceipts:c.accepted, rejectedReceipts:c.rejected, quarantinedReceipts:c.quarantined, disputedReceipts:c.disputed, replayCoverage:c.replay, validatorQuorum:c.quorum, redTeamStrictness:c.redteam, publicPrivateBoundary:c.boundary, alphaWorkUnitsCleared:c.awu, outcome:c.outcome}, lifecycle:['SponsorMandate','PaymasterBudgetEnvelope','NettingHouseReceiptBatch','AlphaFactoryWorkSwarm','ProofBundleExport','ChallengeWindow','AGIJobManagerCheckpoint','ChronicleHandoff'], decision:c.clear?'REVIEW_READY_FOR_SETTLEMENT_CHECKPOINT':'NEEDS_MORE_PROOF_OR_QUARANTINE', claimBoundary:'Local public demonstration only. This JSON is not an on-chain transaction, not a wallet instruction, not a token route, not factual certification, and not production authority.' }; }
  function renderRoots(c){ $('rootsGrid').innerHTML = rootNames.map(n=>`<div class="me-root"><b>${n}</b><code>${c.roots[n]}</code></div>`).join(''); }
  function renderDocket(d){ $('epochJson').textContent = JSON.stringify(d,null,2); $('epochId').textContent = `epoch: ${d.mandate.epochId}`; $('epochState').textContent = d.clearing.outcome; $('acceptedCount').textContent = d.clearing.acceptedReceipts; $('quarantineCount').textContent = d.clearing.quarantinedReceipts; $('disputeCount').textContent = d.clearing.disputedReceipts; $('awuCount').textContent = d.clearing.alphaWorkUnitsCleared; $('heroReceipts').textContent = d.clearing.microjobReceipts; renderRoots({roots:d.publicRoots}); }
  function runPhase(label, active){ renderStages(active); trace(label); state.docket = docket(); renderDocket(state.docket); }
  function download(name, obj){ const blob = new Blob([JSON.stringify(obj,null,2)],{type:'application/json'}); const a=document.createElement('a'); a.href=URL.createObjectURL(blob); a.download=name; document.body.appendChild(a); a.click(); URL.revokeObjectURL(a.href); a.remove(); }
  $('mandatePreset').addEventListener('change', e => { $('mandateObjective').value = presets[e.target.value]; });
  document.querySelectorAll('.me-sliders input').forEach(i=>i.addEventListener('input',()=>{updateSliderLabels(); if(state.opened){ state.docket=docket(); renderDocket(state.docket); }}));
  $('openEpoch').addEventListener('click',()=>{ state.opened=true; state.cleared=false; state.challenged=false; state.finalized=false; $('traceLog').textContent=''; runPhase('Sponsor mandate admitted. Paymaster envelope simulated. No funds moved.',1); });
  $('clearReceipts').addEventListener('click',()=>{ if(!state.opened) $('openEpoch').click(); state.cleared=true; runPhase('NettingHouse batch generated receiptRoot, payoutRoot, archiveDeltaRoot, and quarantineRoot.',4); });
  $('challengeReceipts').addEventListener('click',()=>{ if(!state.cleared) $('clearReceipts').click(); state.challenged=true; runPhase('Challenge window opened. Disputed and quarantined receipts isolated before settlement authority.',6); });
  $('finalizeEpoch').addEventListener('click',()=>{ if(!state.challenged) $('challengeReceipts').click(); state.finalized=true; runPhase('AGIJobManager-compatible checkpoint prepared. Chronicle handoff remains human-review-bound.',7); });
  $('resetEpoch').addEventListener('click',()=>{ state.opened=state.cleared=state.challenged=state.finalized=false; $('traceLog').textContent=''; $('epochJson').textContent='Run the clearinghouse to generate a MandateEpochReceipt.'; $('epochState').textContent='WAITING_FOR_MANDATE'; $('epochId').textContent='epoch: —'; ['acceptedCount','quarantineCount','disputeCount','awuCount'].forEach(id=>$(id).textContent='—'); renderStages(0); renderRoots({roots:Object.fromEntries(rootNames.map(n=>[n,'—']))}); });
  $('downloadEpoch').addEventListener('click',()=>download('mandate-epoch-receipt-public-demo.json', state.docket || docket()));
  $('copyEpochBrief').addEventListener('click',async()=>{ const d=state.docket || docket(); const brief=`MandateEpoch ${d.mandate.epochId}: ${d.clearing.acceptedReceipts}/${d.clearing.microjobReceipts} receipts accepted, ${d.clearing.quarantinedReceipts} quarantined, ${d.clearing.disputedReceipts} disputed, ${d.clearing.alphaWorkUnitsCleared} α-WU cleared. Decision: ${d.decision}. Public demo only; no wallet, no network, no transaction.`; try{ await navigator.clipboard.writeText(brief); trace('Review brief copied.'); }catch(e){ trace(brief); } });
  function stars(){ const canvas=$('meField'), ctx=canvas.getContext('2d'); let w,h,dots=[]; function resize(){ w=canvas.width=innerWidth; h=canvas.height=innerHeight; dots=Array.from({length:Math.min(160,Math.floor(w*h/12000))},()=>({x:Math.random()*w,y:Math.random()*h,r:Math.random()*1.8+.35,v:Math.random()*.38+.08,a:Math.random()*.8+.2})); } addEventListener('resize',resize,{passive:true}); resize(); (function tick(){ ctx.clearRect(0,0,w,h); for(const d of dots){ d.y-=d.v; if(d.y<-10){d.y=h+10;d.x=Math.random()*w;} ctx.globalAlpha=d.a; const g=ctx.createRadialGradient(d.x,d.y,0,d.x,d.y,d.r*4); g.addColorStop(0,'rgba(111,255,225,.9)'); g.addColorStop(1,'rgba(111,255,225,0)'); ctx.fillStyle=g; ctx.beginPath(); ctx.arc(d.x,d.y,d.r*4,0,Math.PI*2); ctx.fill(); } requestAnimationFrame(tick); })(); }
  updateSliderLabels(); renderStages(0); renderRoots({roots:Object.fromEntries(rootNames.map(n=>[n,'—']))}); stars();
})();
